import { motion } from "framer-motion";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Button } from "@/components/ui/button";
import { Phone, Mail, MapPin } from "lucide-react";
import { useState } from "react";
import Navigation from "@/components/Navigation";
import Footer from "@/components/Footer";

export default function Contacts() {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [phone, setPhone] = useState("");
  const [message, setMessage] = useState("");
  const [submitted, setSubmitted] = useState(false);

  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError("");
    setSuccess(false);

    // Client-side validation
    if (!name.trim() || name.trim().length < 2) {
      setError("Please enter your full name (at least 2 characters)");
      setLoading(false);
      return;
    }

    if (!email.trim() || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      setError("Please enter a valid email address");
      setLoading(false);
      return;
    }

    if (!message.trim() || message.trim().length < 10) {
      setError("Message must be at least 10 characters long");
      setLoading(false);
      return;
    }

    const payload = {
      full_name: name.trim(),
      email: email.trim(),
      phone: phone.trim() || null,
      message: message.trim(),
    };

    try {
      const apiUrl = import.meta.env.VITE_API_URL || "http://localhost:5000";
      const res = await fetch(`${apiUrl}/api/contact`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(payload),
      });

      const data = await res.json();

      if (!res.ok) {
        if (data.errors && Array.isArray(data.errors)) {
          setError(data.errors.join(", "));
        } else {
          setError(data.error || "Failed to send message");
        }
        return;
      }

      setSuccess(true);
      setSubmitted(true);
      setName("");
      setEmail("");
      setPhone("");
      setMessage("");
    } catch (err) {
      console.error("Contact form error:", err);
      setError("Something went wrong. Please check your connection and try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 px-6 py-20">
      <div className="max-w-4xl mx-auto text-center mb-12">
        <motion.h1 className="text-4xl font-bold text-primary" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}>
          Contact Us
        </motion.h1>
        <p className="mt-4 text-gray-600 text-lg">We would love to hear from you. Use the form or the contact details below.</p>
      </div>

      <div className="max-w-6xl mx-auto grid md:grid-cols-2 gap-12 items-start">
        <motion.div initial={{ opacity: 0, x: -30 }} animate={{ opacity: 1, x: 0 }} transition={{ duration: 0.5 }} className="space-y-6">
          <div className="flex items-start gap-4">
            <MapPin className="text-gold w-6 h-6 mt-1" />
            <div>
              <h3 className="font-semibold">Location</h3>
              <p className="text-gray-600">Jesus Manifestation Church<br />Kitui County, Kenya</p>
            </div>
          </div>

          <div className="flex items-start gap-4">
            <Phone className="text-gold w-6 h-6 mt-1" />
            <div>
              <h3 className="font-semibold">Phone</h3>
              <p className="text-gray-600">+254 701 504 560</p>
            </div>
          </div>

          <div className="flex items-start gap-4">
            <Mail className="text-gold w-6 h-6 mt-1" />
            <div>
              <h3 className="font-semibold">Email</h3>
              <p className="text-gray-600">jmckitui@gmail.com</p>
            </div>
          </div>

          <div className="mt-6">
            <div className="aspect-[16/9] w-full rounded-lg overflow-hidden border">
              <iframe
                title="Jesus Manifestation Church Map"
                src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d63820.607000139156!2d37.922412761184816!3d-1.3021761134670427!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x18245371df3859df%3A0x4c43808b5e4d1d75!2sJesus%20Manifestation%20Church!5e0!3m2!1sen!2ske!4v1770663176099!5m2!1sen!2ske"
                width="600"
                height="450"
                className="w-full h-full"
                style={{ border: 0 }}
                allowFullScreen=""
                loading="lazy"
                referrerPolicy="no-referrer-when-downgrade"
              />
            </div>
            <p className="text-sm text-gray-500 mt-2">Click the map to open in Google Maps, or use the "Get Directions" button on the home page.</p>
          </div>
        </motion.div>

        <motion.div initial={{ opacity: 0, x: 30 }} animate={{ opacity: 1, x: 0 }} transition={{ duration: 0.5 }} className="bg-white rounded-xl shadow-sm p-8">
          <form className="space-y-6" onSubmit={handleSubmit}>
            {error && (
              <motion.div
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                className="p-4 bg-red-50 border border-red-200 rounded-lg"
              >
                <p className="text-red-700 font-medium text-sm">{error}</p>
              </motion.div>
            )}

            {submitted && success && (
              <motion.div
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                className="p-4 bg-green-50 border border-green-200 rounded-lg"
              >
                <p className="text-green-700 font-medium text-sm">Γ£ô Thank you for reaching out! We will get back to you soon.</p>
              </motion.div>
            )}

            <div>
              <label htmlFor="fullName" className="block text-sm font-medium mb-1">Full Name <span className="text-red-500">*</span></label>
              <Input id="fullName" value={name} onChange={(e) => setName(e.target.value)} placeholder="Your full name" required />
            </div>

            <div>
              <label htmlFor="email" className="block text-sm font-medium mb-1">Email Address <span className="text-red-500">*</span></label>
              <Input id="email" type="email" value={email} onChange={(e) => setEmail(e.target.value)} placeholder="you@example.com" required />
            </div>

            <div>
              <label htmlFor="phone" className="block text-sm font-medium mb-1">Phone Number</label>
              <Input id="phone" value={phone} onChange={(e) => setPhone(e.target.value)} placeholder="+254..." />
            </div>

            <div>
              <label htmlFor="message" className="block text-sm font-medium mb-1">Message <span className="text-red-500">*</span> (min 10 chars)</label>
              <Textarea id="message" value={message} onChange={(e) => setMessage(e.target.value)} placeholder="Write your message here..." className="min-h-[120px]" required />
            </div>

            <Button type="submit" disabled={loading} className="w-full bg-primary text-white">{loading ? "Sending..." : "Send Message"}</Button>
          </form>
        </motion.div>

      </div>
      <p className="text-xs text-gray-400 text-center mt-4">Your information is kept private and used only for church communication.</p>
    </div>
  );
}

import { motion } from "framer-motion";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Button } from "@/components/ui/button";
import { Phone, Mail, MapPin } from "lucide-react";
import { useState } from "react";
import Navigation from "@/components/Navigation";
import Footer from "@/components/Footer";

export default function Contacts() {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [phone, setPhone] = useState("");
  const [message, setMessage] = useState("");

  const [loading, setLoading] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [error, setError] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError("");

    // Client-side validation
    if (!name.trim() || name.trim().length < 2) {
      setError("Please enter your full name (at least 2 characters)");
      setLoading(false);
      return;
    }

    if (!email.trim() || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      setError("Please enter a valid email address");
      setLoading(false);
      return;
    }

    if (!message.trim() || message.trim().length < 10) {
      setError("Message must be at least 10 characters long");
      setLoading(false);
      return;
    }

    const payload = {
      full_name: name.trim(),
      email: email.trim(),
      phone: phone.trim() || null,
      message: message.trim(),
    };

    try {
      const apiUrl = import.meta.env.VITE_API_URL || "http://localhost:5000";
      const res = await fetch(`${apiUrl}/api/contact`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      const data = await res.json();

      if (!res.ok) {
        // Handle server validation errors
        if (data.errors && Array.isArray(data.errors)) {
          setError(data.errors.join(", "));
        } else {
          setError(data.error || "Failed to send message");
        }
        return;
      }

      setSubmitted(true);
      setName("");
      setEmail("");
      setPhone("");
      setMessage("");
    } catch (err) {
      console.error("Contact form error:", err);
      setError("Something went wrong. Please check your connection and try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col dark:bg-slate-950 transition-colors duration-300">
      <Navigation />

      <main className="flex-1 px-6 py-20 bg-gray-50 dark:bg-slate-950 transition-colors duration-300">
        <div className="max-w-4xl mx-auto text-center mb-12">
          <motion.h1 className="text-4xl font-bold text-primary dark:text-white transition-colors" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}>
            Contact Us
          </motion.h1>
          <p className="mt-4 text-gray-600 dark:text-gray-300 text-lg transition-colors">We would love to hear from you. Use the form or the contact details below.</p>
        </div>

        <div className="max-w-6xl mx-auto grid md:grid-cols-2 gap-12 items-start">
          <motion.div initial={{ opacity: 0, x: -30 }} animate={{ opacity: 1, x: 0 }} transition={{ duration: 0.5 }} className="space-y-6">
            <div className="flex items-start gap-4">
              <MapPin className="text-gold w-6 h-6 mt-1" />
              <div>
                <h3 className="font-semibold dark:text-white transition-colors">Location</h3>
                <p className="text-gray-600 dark:text-gray-400 transition-colors">Jesus Manifestation Church<br />Kitui County, Kenya</p>
              </div>
            </div>

            <div className="flex items-start gap-4">
              <Phone className="text-gold w-6 h-6 mt-1" />
              <div>
                <h3 className="font-semibold dark:text-white transition-colors">Phone</h3>
                <p className="text-gray-600 dark:text-gray-400 transition-colors">+254 701 504 560</p>
              </div>
            </div>

            <div className="flex items-start gap-4">
              <Mail className="text-gold w-6 h-6 mt-1" />
              <div>
                <h3 className="font-semibold dark:text-white transition-colors">Email</h3>
                <p className="text-gray-600 dark:text-gray-400 transition-colors">jmckitui@gmail.com</p>
              </div>
            </div>

            <div className="mt-6">
              <div className="aspect-[16/9] w-full rounded-lg overflow-hidden border dark:border-slate-800 transition-colors">
                <iframe
                  title="Jesus Manifestation Church Map"
                  src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d63820.607000139156!2d37.922412761184816!3d-1.3021761134670427!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x18245371df3859df%3A0x4c43808b5e4d1d75!2sJesus%20Manifestation%20Church!5e0!3m2!1sen!2ske!4v1770663176099!5m2!1sen!2ske"
                  width="600"
                  height="450"
                  className="w-full h-full"
                  style={{ border: 0 }}
                  allowFullScreen=""
                  loading="lazy"
                  referrerPolicy="no-referrer-when-downgrade"
                />
              </div>
              <p className="text-sm text-gray-500 dark:text-gray-400 mt-2 transition-colors">Click the map to open in Google Maps, or use the "Get Directions" button on the home page.</p>
            </div>
          </motion.div>

          <motion.div initial={{ opacity: 0, x: 30 }} animate={{ opacity: 1, x: 0 }} transition={{ duration: 0.5 }} className="bg-white dark:bg-slate-900 border border-transparent dark:border-slate-800 rounded-xl shadow-sm p-8 transition-colors">
            <form className="space-y-6" onSubmit={handleSubmit}>
              {error && (
                <motion.div
                  initial={{ opacity: 0, y: -10 }}
                  animate={{ opacity: 1, y: 0 }}
                  className="p-4 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-900/50 rounded-lg transition-colors"
                >
                  <p className="text-red-700 dark:text-red-400 font-medium text-sm transition-colors">{error}</p>
                </motion.div>
              )}

              {submitted && (
                <motion.div
                  initial={{ opacity: 0, y: -10 }}
                  animate={{ opacity: 1, y: 0 }}
                  className="p-4 bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-900/50 rounded-lg transition-colors"
                >
                  <p className="text-green-700 dark:text-green-400 font-medium text-sm transition-colors">Γ£ô Thank you for reaching out! We will get back to you soon.</p>
                </motion.div>
              )}

              <div>
                <label htmlFor="fullName" className="block text-sm font-medium mb-1 dark:text-white transition-colors">Full Name <span className="text-red-500">*</span></label>
                <Input id="fullName" value={name} onChange={(e) => setName(e.target.value)} placeholder="Your full name" required className="dark:bg-slate-800 dark:border-slate-700 dark:text-white transition-colors" />
              </div>

              <div>
                <label htmlFor="email" className="block text-sm font-medium mb-1 dark:text-white transition-colors">Email Address <span className="text-red-500">*</span></label>
                <Input id="email" type="email" value={email} onChange={(e) => setEmail(e.target.value)} placeholder="you@example.com" required className="dark:bg-slate-800 dark:border-slate-700 dark:text-white transition-colors" />
              </div>

              <div>
                <label htmlFor="phone" className="block text-sm font-medium mb-1 dark:text-white transition-colors">Phone Number</label>
                <Input id="phone" value={phone} onChange={(e) => setPhone(e.target.value)} placeholder="+254..." className="dark:bg-slate-800 dark:border-slate-700 dark:text-white transition-colors" />
              </div>

              <div>
                <label htmlFor="message" className="block text-sm font-medium mb-1 dark:text-white transition-colors">Message <span className="text-red-500">*</span> (min 10 chars)</label>
                <Textarea id="message" value={message} onChange={(e) => setMessage(e.target.value)} placeholder="Write your message here..." className="min-h-[120px] dark:bg-slate-800 dark:border-slate-700 dark:text-white transition-colors" required />
              </div>

              <Button type="submit" disabled={loading} className="w-full bg-primary text-white">{loading ? "Sending..." : "Send Message"}</Button>
            </form>
          </motion.div>

        </div>
        <p className="text-xs text-gray-400 dark:text-gray-500 text-center mt-4 transition-colors">Your information is kept private and used only for church communication.</p>
      </main>

      <Footer />
    </div>
  );
}

import { useParams, Link } from "react-router-dom";
import { getDevotionalById } from "../Data/Devotionals";
import { Calendar, User, BookOpen, ArrowLeft } from "lucide-react";
import { motion } from "framer-motion";
import Navigation from "../components/Navigation";
import Footer from "../components/Footer";

export default function DevotionalDetail() {
  const { id } = useParams();
  console.log("URL ID:", id); // DEBUG

  const devotional = getDevotionalById(id);
  console.log("Found devotional:", devotional); // DEBUG

  if (!devotional) {
    console.log("Devotional not found!"); // DEBUG
    return (
      <div className="min-h-screen flex flex-col dark:bg-slate-950 transition-colors duration-300">
        <Navigation />
        <div className="flex-1 px-6 py-20 bg-white dark:bg-slate-950 flex items-center justify-center transition-colors duration-300">
          <div className="text-center">
            <h1 className="text-3xl font-bold text-gray-900 dark:text-white mb-4 transition-colors">Devotional Not Found</h1>
            <p className="text-gray-600 dark:text-gray-400 mb-4 transition-colors">Looking for ID: {id}</p>
            <Link to="/devotionals" className="text-purple-600 dark:text-purple-400 hover:text-purple-700 dark:hover:text-purple-300 hover:underline transition-colors">
              ΓåÉ Back to Devotionals
            </Link>
          </div>
        </div>
        <Footer />
      </div>
    );
  }

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric'
    });
  };

  return (
    <div className="min-h-screen flex flex-col dark:bg-slate-950 transition-colors duration-300">
      <Navigation />

      <div className="flex-1 px-4 sm:px-6 py-20">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="max-w-3xl mx-auto"
        >
          {/* Back Button */}
          <Link
            to="/devotionals"
            className="inline-flex items-center gap-2 text-purple-600 dark:text-purple-400 hover:text-purple-700 dark:hover:text-purple-300 mb-6 font-medium transition-colors"
          >
            <ArrowLeft size={20} />
            Back to Devotionals
          </Link>

          {/* Article */}
          <article className="bg-white dark:bg-slate-900 border border-transparent dark:border-slate-800 rounded-xl shadow-lg p-6 sm:p-10 transition-colors duration-300">
            <h1 className="text-3xl sm:text-4xl font-bold text-gray-900 dark:text-white mb-4 transition-colors">
              {devotional.title}
            </h1>

            <div className="flex flex-wrap items-center gap-4 text-sm text-gray-600 dark:text-gray-400 border-b dark:border-slate-800 mb-6 pb-6 transition-colors">
              <span className="flex items-center gap-2">
                <Calendar size={18} />
                {formatDate(devotional.date)}
              </span>
              {devotional.author && (
                <span className="flex items-center gap-2">
                  <User size={18} />
                  {devotional.author}
                </span>
              )}
              {devotional.category && (
                <span className="bg-purple-100 dark:bg-purple-900/40 text-purple-700 dark:text-purple-300 px-3 py-1 rounded-full text-xs font-semibold transition-colors">
                  {devotional.category}
                </span>
              )}
            </div>

            <div className="bg-purple-50 dark:bg-purple-900/20 border-l-4 border-purple-600 dark:border-purple-500 p-4 mb-6 transition-colors">
              <div className="flex items-start gap-2">
                <BookOpen className="text-purple-600 dark:text-purple-400 mt-1 transition-colors" size={20} />
                <div>
                  <p className="font-semibold text-purple-900 dark:text-purple-300 transition-colors">{devotional.scripture}</p>
                  <p className="text-gray-700 dark:text-gray-300 italic mt-1 transition-colors">"{devotional.excerpt}"</p>
                </div>
              </div>
            </div>

            <div className="prose prose-lg max-w-none">
              {devotional.content.split('\n\n').map((paragraph, index) => (
                <p key={index} className="text-gray-700 dark:text-gray-300 mb-4 leading-relaxed transition-colors">
                  {paragraph}
                </p>
              ))}
            </div>
          </article>

          {/* Navigation to other devotionals */}
          <div className="mt-8 text-center">
            <Link
              to="/devotionals"
              className="inline-flex items-center gap-2 px-6 py-3 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition font-semibold"
            >
              View All Devotionals
            </Link>
          </div>
        </motion.div>
      </div>

      <Footer />
    </div>
  );
}

import { useState } from "react";
import { Link } from "react-router-dom";
import { devotionals } from "../Data/Devotionals";
import { Calendar, User, BookOpen } from "lucide-react";
import { motion } from "framer-motion";
import Navigation from "../components/Navigation";
import Footer from "../components/Footer";

export default function Devotionals() {
  const [searchTerm, setSearchTerm] = useState("");

  const filteredDevotionals = devotionals.filter(dev =>
    dev.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    dev.excerpt.toLowerCase().includes(searchTerm.toLowerCase()) ||
    dev.scripture.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric'
    });
  };

  return (
    <div className="min-h-screen flex flex-col dark:bg-slate-950 transition-colors duration-300">
      {/* NAVIGATION - This should appear at the top */}
      <Navigation />

      <div className="flex-1 px-4 sm:px-6 py-20">
        <div className="max-w-6xl mx-auto">
          {/* Header */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="text-center mb-12"
          >
            <h1 className="text-4xl md:text-5xl font-bold text-purple-900 dark:text-white mb-4 transition-colors">
              Daily Devotionals
            </h1>
            <p className="text-lg text-gray-600 dark:text-gray-300 max-w-2xl mx-auto transition-colors">
              Short daily reflections to encourage your walk with God
            </p>
          </motion.div>

          {/* Search Bar */}
          <div className="mb-8 max-w-xl mx-auto">
            <input
              type="text"
              placeholder="Search devotionals..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full px-4 py-3 rounded-lg border border-gray-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-gray-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-purple-500 transition-colors"
            />
          </div>

          {/* Devotionals Grid */}
          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredDevotionals.map((devotional, index) => (
              <motion.div
                key={devotional.id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: index * 0.1 }}
              >
                <Link
                  to={`/devotionals/${devotional.id}`}
                  className="block bg-white dark:bg-slate-900 border border-transparent dark:border-slate-800 rounded-xl shadow-md hover:shadow-xl transition-all duration-300 overflow-hidden h-full"
                >
                  {devotional.image && (
                    <img
                      src={devotional.image}
                      alt={devotional.title}
                      className="w-full h-48 object-cover"
                    />
                  )}

                  <div className="p-6">
                    <div className="flex items-center gap-4 text-sm text-gray-500 dark:text-gray-400 mb-3 transition-colors">
                      <span className="flex items-center gap-1">
                        <Calendar size={16} />
                        {formatDate(devotional.date)}
                      </span>
                      {devotional.author && (
                        <span className="flex items-center gap-1">
                          <User size={16} />
                          {devotional.author}
                        </span>
                      )}
                    </div>

                    <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-2 transition-colors">
                      {devotional.title}
                    </h2>

                    <div className="flex items-center gap-2 text-purple-600 dark:text-purple-400 text-sm mb-3 transition-colors">
                      <BookOpen size={16} />
                      <span className="font-medium">{devotional.scripture}</span>
                    </div>

                    <p className="text-gray-600 dark:text-gray-400 line-clamp-3 transition-colors">
                      {devotional.excerpt}
                    </p>

                    <div className="mt-4 text-purple-600 dark:text-purple-400 font-semibold text-sm transition-colors">
                      Read More ΓåÆ
                    </div>
                  </div>
                </Link>
              </motion.div>
            ))}
          </div>

          {filteredDevotionals.length === 0 && (
            <div className="text-center py-12">
              <p className="text-gray-500 dark:text-gray-400 text-lg transition-colors">No devotionals found matching your search.</p>
            </div>
          )}
        </div>
      </div>

      {/* FOOTER - This should appear at the bottom */}
      <Footer />
    </div>
  );
}

