                );
              })()}

              {/* Additional recent sermons as smaller cards */}
              {latestSermons.length > 1 && (
                <div className="grid md:grid-cols-2 gap-6">
                  {latestSermons.slice(1).map((sermon, index) => {
                    const youtubeId = extractYoutubeId(sermon.video_url);
                    return (
                      <motion.div
